@using sv_8dcc7fb8829e483ab3b0048a59115404.Services
@inject ISettingsService SettingsService

<div class="settings-section appearance-section">
    <h2>Appearance Settings</h2>

    @if (_loading)
    {
        <p>Loading...</p>
    }
    else
    {
        <!-- Theme Selector -->
        <div class="form-group">
            <label>Theme</label>
            <div class="radio-group">
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <label class="radio-item">
                        <input type="radio" name="theme" value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <span>@theme</span>
                    </label>
                }
            </div>
        </div>

        <!-- Font Size Selector -->
        <div class="form-group">
            <label>Font Size</label>
            <div class="radio-group">
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <label class="radio-item">
                        <input type="radio" name="fontSize" value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <span>@size</span>
                    </label>
                }
            </div>
        </div>

        <!-- Language Dropdown -->
        <div class="form-group">
            <label for="language">Language</label>
            <select id="language" @bind="_language">
                <option value="English">English</option>
                <option value="Spanish">Spanish</option>
                <option value="French">French</option>
                <option value="German">German</option>
                <option value="Japanese">Japanese</option>
            </select>
        </div>

        <!-- Compact Mode -->
        <div class="form-group">
            <label class="toggle-item">
                <input type="checkbox" @bind="_compactMode" />
                <span>Compact Mode</span>
            </label>
        </div>

        <!-- Live Preview -->
        <div class="live-preview @GetPreviewClasses()">
            <h4>Preview</h4>
            <p>This is how your content will look with the selected settings.</p>
            <div class="preview-card">
                <strong>Sample Card</strong>
                <p>Lorem ipsum dolor sit amet, consectetur adipiscing elit.</p>
                <button class="btn-primary">Action</button>
            </div>
        </div>

        <div class="form-actions">
            <button class="btn-primary" @onclick="SaveAppearance">Save</button>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="toast-message success">@_message</div>
        }
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _loading = true;
    private string _message = "";

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _message = "Appearance settings saved!";
    }

    private string GetPreviewClasses()
    {
        var classes = $"theme-{_theme.ToLowerInvariant()} font-{_fontSize.ToLowerInvariant()}";
        if (_compactMode) classes += " compact";
        return classes;
    }
}

