<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="SetActiveSection" />

    <main class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </main>
</div>

@code {
    private string _activeSection = "Profile";

    private void SetActiveSection(string section)
    {
        _activeSection = section;
    }
}

.settings-layout {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
}

/* Sidebar */
.settings-sidebar {
    width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #e0e0e0;
    padding: 1rem 0;
    flex-shrink: 0;
}

.settings-sidebar ul {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-sidebar li {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
    color: #555;
}

.settings-sidebar li:hover {
    background: #e9ecef;
    color: #333;
}

.settings-sidebar li.active {
    background: #e3f2fd;
    border-left-color: #1976d2;
    color: #1976d2;
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.1rem;
}

/* Content Area */
.settings-content {
    flex: 1;
    padding: 2rem;
    max-width: 800px;
}

.settings-section h2 {
    margin-top: 0;
    margin-bottom: 1.5rem;
    font-size: 1.5rem;
    color: #333;
}

.settings-section h3 {
    margin-top: 1.5rem;
    margin-bottom: 0.75rem;
    font-size: 1.1rem;
    color: #555;
}

/* Form Elements */
.form-group {
    margin-bottom: 1.25rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.4rem;
    font-weight: 500;
    color: #444;
}

.form-group input[type="text"],
.form-group input[type="email"],
.form-group input[type="password"],
.form-group textarea,
.form-group select {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 6px;
    font-size: 0.95rem;
    transition: border-color 0.15s;
}

.form-group input:focus,
.form-group textarea:focus,
.form-group select:focus {
    outline: none;
    border-color: #1976d2;
    box-shadow: 0 0 0 2px rgba(25, 118, 210, 0.1);
}

/* Buttons */
.form-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

.btn-primary {
    background: #1976d2;
    color: white;
    border: none;
    padding: 0.6rem 1.25rem;
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.9rem;
    font-weight: 500;
    transition: background 0.15s;
}

.btn-primary:hover {
    background: #1565c0;
}

.btn-secondary {
    background: #f5f5f5;
    color: #555;
    border: 1px solid #ddd;
    padding: 0.6rem 1.25rem;
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.9rem;
    font-weight: 500;
    transition: background 0.15s;
}

.btn-secondary:hover {
    background: #e0e0e0;
}

.btn-danger {
    background: #d32f2f;
    color: white;
    border: none;
    padding: 0.6rem 1.25rem;
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.9rem;
    font-weight: 500;
}

.btn-danger:hover {
    background: #b71c1c;
}

.btn-small {
    padding: 0.3rem 0.75rem;
    font-size: 0.8rem;
}

/* Toast Messages */
.toast-message {
    margin-top: 1rem;
    padding: 0.75rem 1rem;
    border-radius: 6px;
    font-size: 0.9rem;
}

.toast-message.success {
    background: #e8f5e9;
    color: #2e7d32;
    border: 1px solid #c8e6c9;
}

.toast-message.error {
    background: #ffebee;
    color: #c62828;
    border: 1px solid #ffcdd2;
}

.toast-message.info {
    background: #e3f2fd;
    color: #1565c0;
    border: 1px solid #bbdefb;
}

/* Avatar */
.avatar-preview {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 1.5rem;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 8px;
}

.avatar-image {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #e0e0e0;
}

.avatar-url {
    color: #777;
    font-size: 0.85rem;
    word-break: break-all;
}

/* Toggle Items */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

.toggle-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
}

.toggle-item input[type="checkbox"] {
    width: 18px;
    height: 18px;
    accent-color: #1976d2;
}

/* Channel List */
.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    padding: 0.75rem;
    background: #f8f9fa;
    border-radius: 6px;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
}

.channel-item input[type="checkbox"] {
    accent-color: #1976d2;
}

/* Expandable Panel */
.expandable-panel {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    margin-bottom: 1.5rem;
    overflow: hidden;
}

.panel-header {
    width: 100%;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.85rem 1.25rem;
    background: #f8f9fa;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    font-weight: 500;
    color: #333;
}

.panel-header:hover {
    background: #e9ecef;
}

.panel-content {
    padding: 1.25rem;
    border-top: 1px solid #e0e0e0;
}

/* 2FA Section */
.twofa-section {
    margin-bottom: 1.5rem;
}

.twofa-status {
    display: flex;
    align-items: center;
    gap: 0.75rem;
}

.status-indicator {
    font-size: 1.2rem;
}

.status-indicator.enabled {
    color: #2e7d32;
}

.status-indicator.disabled {
    color: #999;
}

.last-change {
    font-size: 0.85rem;
    color: #777;
    margin-top: 0.5rem;
}

.current-badge {
    background: #e3f2fd;
    color: #1976d2;
    padding: 0.2rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
}

/* Sessions Table */
.sessions-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 0.75rem;
}

.sessions-table th,
.sessions-table td {
    padding: 0.6rem 0.75rem;
    text-align: left;
    border-bottom: 1px solid #e0e0e0;
}

.sessions-table th {
    background: #f8f9fa;
    font-weight: 600;
    font-size: 0.85rem;
    color: #555;
    text-transform: uppercase;
    letter-spacing: 0.03em;
}

.sessions-table td {
    font-size: 0.9rem;
}

/* Radio Group */
.radio-group {
    display: flex;
    gap: 1.25rem;
    margin-top: 0.25rem;
}

.radio-item {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
}

.radio-item input[type="radio"] {
    accent-color: #1976d2;
}

/* Live Preview */
.live-preview {
    margin-top: 1.5rem;
    padding: 1.5rem;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    transition: all 0.2s ease;
}

.live-preview h4 {
    margin-top: 0;
    margin-bottom: 0.5rem;
}

.live-preview .preview-card {
    margin-top: 1rem;
    padding: 1rem;
    border: 1px solid #ddd;
    border-radius: 6px;
}

/* Theme Variants */
.live-preview.theme-light {
    background: #ffffff;
    color: #333;
}

.live-preview.theme-dark {
    background: #1e1e1e;
    color: #e0e0e0;
    border-color: #444;
}

.live-preview.theme-dark .preview-card {
    background: #2d2d2d;
    border-color: #555;
}

.live-preview.theme-system {
    background: #f5f5f5;
    color: #333;
}

/* Font Size Variants */
.live-preview.font-small {
    font-size: 0.8rem;
}

.live-preview.font-medium {
    font-size: 1rem;
}

.live-preview.font-large {
    font-size: 1.2rem;
}

/* Compact Mode */
.live-preview.compact {
    padding: 0.75rem;
    line-height: 1.3;
}

.live-preview.compact .preview-card {
    padding: 0.5rem;
    margin-top: 0.5rem;
}

/* Dialog */
.dialog-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

.dialog {
    background: white;
    padding: 1.5rem;
    border-radius: 10px;
