    width: 90%;
    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);
}

.dialog h4 {
    margin-top: 0;
    margin-bottom: 0.75rem;
}

.dialog-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.25rem;
    justify-content: flex-end;
}

